// ── EMBED PHOTO (base64 so no external file needed) ──
const PHOTO_B64 = "";
document.addEventListener("DOMContentLoaded", () => {
  const img = document.getElementById("hero-photo");
  if (img && PHOTO_B64 && PHOTO_B64 !== "") {
    img.src = "data:image/png;base64," + PHOTO_B64;
  }

  // ── NAVBAR SCROLL SHADOW ──
  const navbar = document.getElementById("navbar");
  window.addEventListener("scroll", () => {
    navbar.classList.toggle("scrolled", window.scrollY > 20);
  });

  // ── SCROLL REVEAL ──
  const revealEls = document.querySelectorAll(
    ".timeline-card, .skill-card, .edu-card, .about-body, .stat, .contact-card"
  );
  revealEls.forEach(el => el.classList.add("reveal"));

  const observer = new IntersectionObserver((entries) => {
    entries.forEach((entry, i) => {
      if (entry.isIntersecting) {
        setTimeout(() => {
          entry.target.classList.add("visible");
        }, 80 * (entry.target.dataset.delay || 0));
        observer.unobserve(entry.target);
      }
    });
  }, { threshold: 0.12 });

  revealEls.forEach((el, i) => {
    el.dataset.delay = i % 4;
    observer.observe(el);
  });

  // ── ACTIVE NAV LINK ──
  const sections = document.querySelectorAll("section[id]");
  const navLinks = document.querySelectorAll(".nav-links a");
  const activateNav = () => {
    let current = "";
    sections.forEach(sec => {
      if (window.scrollY >= sec.offsetTop - 100) current = sec.id;
    });
    navLinks.forEach(a => {
      a.style.color = a.getAttribute("href") === `#${current}` ? "var(--teal)" : "";
    });
  };
  window.addEventListener("scroll", activateNav);
});
